class Solution:
    def makeIntegerBeautiful(self, n, target):
        def dsum(x):
            return sum(int(c) for c in str(x))
        s = str(n)
        L = len(s)
        # try zeroing the last k digits by rounding up via string arithmetic
        for k in range(L + 1):
            if k == 0:
                cand = n
            else:
                head = s[:L - k]
                head_val = int(head) if head else 0
                base = (head_val + 1) * (10 ** k)
                cand = base
            if dsum(cand) <= target:
                return cand - n
        return (10 ** L) - n

