class Solution:
    def makeIntegerBeautiful(self, n, target):
        def dsum(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s
        p = 1
        cur = n
        while dsum(cur) > target:
            cur = (n // (p * 10) + 1) * (p * 10)
            p *= 10
        return cur - n

