var makeIntegerBeautiful = function(n, target) {
    const dsum = (x) => {
        let s = 0;
        while (x > 0) { s += x % 10; x = Math.floor(x / 10); }
        return s;
    };
    let p = 1;
    let cur = n;
    while (dsum(cur) > target) {
        const step = p * 10;
        cur = (Math.floor(n / step) + 1) * step;
        p = step;
    }
    return cur - n;
};
